import{_ as a,o as t,c as n,ag as o}from"./chunks/framework.wGDfT7ie.js";const u=JSON.parse('{"title":"Layout Export","description":"","frontmatter":{},"headers":[],"relativePath":"development/layout-export.md","filePath":"development/layout-export.md"}'),s={name:"development/layout-export.md"};function r(i,e,d,l,c,p){return t(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="layout-export" tabindex="-1">Layout Export <a class="header-anchor" href="#layout-export" aria-label="Permalink to &quot;Layout Export&quot;">​</a></h1><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of Contents&quot;">​</a></h2><ul><li><a href="#overview">Overview</a></li><li><a href="#architecture">Architecture</a></li><li><a href="#data-model">Data Model</a></li><li><a href="#html-renderer">HTML Renderer</a></li><li><a href="#svg-renderer">SVG Renderer</a></li><li><a href="#integration">Integration</a></li><li><a href="#implementation-notes">Implementation Notes</a></li></ul><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The <code>layout-export</code> module converts a kle-ng keyboard layout into standalone, self-contained files for distribution. It provides two export targets:</p><ul><li><strong>HTML</strong> — a complete document with embedded CSS that renders the keyboard visually in any browser.</li><li><strong>SVG</strong> — a vector graphics file suitable for embedding in documents, editing in vector tools, or printing at any scale.</li></ul><p>Both renderers share a common normalized data model, geometry constants, and utility functions, ensuring visual consistency between the two output formats and with the live canvas in the editor. The module has no Vue or store dependencies — the sole connection point to the application is <code>normalizeLayoutInput</code>, which converts raw <code>Key[]</code> and <code>KeyboardMetadata</code> into a framework-independent structure that the renderers consume.</p><hr><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>layout-export/</span></span>
<span class="line"><span>├── index.ts                   Public API — re-exports from all submodules</span></span>
<span class="line"><span>├── LayoutRendererTypes.ts     Shared type definitions (interfaces only)</span></span>
<span class="line"><span>├── layout-render-constants.ts Numeric constants (bevel geometry, radii, nub)</span></span>
<span class="line"><span>├── layout-render-geometry.ts  Pure geometry functions (inner rect, nub, text Y)</span></span>
<span class="line"><span>├── layout-render-utils.ts     Input normalization and string-safety utilities</span></span>
<span class="line"><span>├── HtmlLayoutRenderer.ts      HTML renderer</span></span>
<span class="line"><span>├── SvgLayoutRenderer.ts       SVG renderer</span></span>
<span class="line"><span>└── __tests__/                 Vitest specs for all submodules</span></span></code></pre></div><p>All consumer imports should come from <code>@/utils/layout-export</code> — never from submodule paths directly.</p><h3 id="data-flow" tabindex="-1">Data Flow <a class="header-anchor" href="#data-flow" aria-label="Permalink to &quot;Data Flow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Key[] + KeyboardMetadata</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>  normalizeLayoutInput()       layout-render-utils.ts</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>   LayoutRenderInput           LayoutRendererTypes.ts</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ├────────────────────────┐</span></span>
<span class="line"><span>         ▼                        ▼</span></span>
<span class="line"><span>HtmlLayoutRenderer.render()  SvgLayoutRenderer.render()</span></span>
<span class="line"><span>         │                        │</span></span>
<span class="line"><span>         ▼                        ▼</span></span>
<span class="line"><span>    string (HTML)            string (SVG)</span></span></code></pre></div><p>Constants in <code>layout-render-constants.ts</code> are derived from <code>KeyRenderer.defaultSizes</code> in the canvas pipeline. This shared source of truth ensures the exported output is visually identical to the editor canvas.</p><hr><h2 id="data-model" tabindex="-1">Data Model <a class="header-anchor" href="#data-model" aria-label="Permalink to &quot;Data Model&quot;">​</a></h2><h3 id="normalization-normalizelayoutinput" tabindex="-1">Normalization: <code>normalizeLayoutInput</code> <a class="header-anchor" href="#normalization-normalizelayoutinput" aria-label="Permalink to &quot;Normalization: \`normalizeLayoutInput\`&quot;">​</a></h3><p><code>normalizeLayoutInput(keys, metadata, filename, unit?)</code> is a pure function that converts raw store data into a renderer-ready <code>LayoutRenderInput</code>. It does the following:</p><ol><li><p><strong>Bounds calculation</strong>: Uses <code>BoundsCalculator</code> to find the rotation-aware axis-aligned bounding box of all keys. Rotated keys&#39; four corners are individually transformed before the box is computed, so board dimensions are always correct even for complex rotated layouts.</p></li><li><p><strong>Coordinate translation</strong>: All key positions are offset so the minimum key corner sits at <code>(LAYOUT_PADDING, LAYOUT_PADDING)</code>. Coordinates in <code>KeyRenderData</code> are ready for direct use by renderers.</p></li><li><p><strong>Label resolution</strong>: For each of the 12 possible label positions, whitespace-only slots are skipped. Each kept label gets a computed pixel <code>fontSize</code> (base formula: <code>6 + 2 * textSize</code>; front legends at positions 9–11 are capped smaller), alignment and baseline derived from the position&#39;s column/row, and anchor coordinates (<code>relX</code>, <code>relY</code>) relative to the key&#39;s outer rect.</p></li><li><p><strong>Color resolution</strong>: The outer bevel color comes from <code>key.color</code> (defaulting to <code>#cccccc</code>). The inner cap color is produced by lightening that color in CIE Lab space, matching the canvas renderer.</p></li><li><p><strong>Special flags</strong>: <code>ghost</code>, <code>decal</code>, <code>nub</code>, and <code>isRotaryEncoder</code> are included only when <code>true</code>.</p></li><li><p><strong>Non-rectangular geometry</strong>: When a key has a second rectangle (ISO Enter, Big-Ass Enter), <code>left2</code>/<code>top2</code>/<code>width2</code>/<code>height2</code> are computed in the same board-space coordinate system as the primary rectangle.</p></li></ol><h3 id="key-types" tabindex="-1">Key Types <a class="header-anchor" href="#key-types" aria-label="Permalink to &quot;Key Types&quot;">​</a></h3><p><strong><code>LayoutRenderInput</code></strong> is the top-level structure passed to each renderer. It carries board dimensions (accounting for rotation), background color, border-radius string, unit size, and the array of <code>KeyRenderData</code>.</p><p><strong><code>KeyRenderData</code></strong> describes a single key in board-space pixels. Coordinates are already padded and translated. Optional fields <code>left2</code>/<code>top2</code>/<code>width2</code>/<code>height2</code> are present only for non-rectangular keys. Special rendering flags (<code>ghost</code>, <code>decal</code>, <code>nub</code>, <code>isRotaryEncoder</code>) are present only when true.</p><p><strong><code>LabelData</code></strong> describes a single label on a key. <code>relX</code>/<code>relY</code> define the anchor point within the key&#39;s outer rect. <code>align</code> (<code>left</code>/<code>center</code>/<code>right</code>) and <code>baseline</code> (<code>hanging</code>/<code>middle</code>/<code>alphabetic</code>) describe how the anchor maps to the text box — these semantics match SVG&#39;s <code>text-anchor</code> and <code>dominant-baseline</code> and are approximated in HTML with arithmetic.</p><p><strong><code>LayoutRenderer</code></strong> is a single-method interface (<code>render(input): string</code>) that both renderers implement. The returned string is ready for use as a <code>Blob</code> for file download.</p><h3 id="label-position-grid" tabindex="-1">Label Position Grid <a class="header-anchor" href="#label-position-grid" aria-label="Permalink to &quot;Label Position Grid&quot;">​</a></h3><p>KLE supports up to 12 label positions per key arranged in a 3×4 grid: a 3×3 top-surface grid plus a row of 3 front-legend positions (side print).</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Top surface:</span></span>
<span class="line"><span>┌────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  [0] top-left  [1] top-ctr  [2] top-right  │</span></span>
<span class="line"><span>│  [3] mid-left  [4] mid-ctr  [5] mid-right  │</span></span>
<span class="line"><span>│  [6] bot-left  [7] bot-ctr  [8] bot-right  │</span></span>
<span class="line"><span>└────────────────────────────────────────────┘</span></span>
<span class="line"><span>Front face:</span></span>
<span class="line"><span>  [9] front-left  [10] front-ctr  [11] front-right</span></span></code></pre></div><p>Column determines <code>align</code> (left/center/right). Row determines <code>baseline</code> (hanging/middle/alphabetic, with front legends using hanging). The alignment and anchor values are baked into each <code>LabelData</code> entry at normalization time, so renderers iterate <code>labels</code> without any awareness of position index.</p><h3 id="constants" tabindex="-1">Constants <a class="header-anchor" href="#constants" aria-label="Permalink to &quot;Constants&quot;">​</a></h3><p>All sizing constants are in <code>layout-render-constants.ts</code>. The key rendering model uses a <strong>two-rectangle structure</strong>: an outer rectangle (dark bevel area, 5px corner radius) and an inner rectangle (lighter keycap surface, 3px corner radius). The inner rect is inset asymmetrically — 6px from the left/right and top (3px inset) and bottom (9px inset) — to simulate the taller lower bevel of a physical keycap. The default unit size is 54px per 1u, matching the editor canvas. A 9px padding is added around the key area on all sides.</p><hr><h2 id="html-renderer" tabindex="-1">HTML Renderer <a class="header-anchor" href="#html-renderer" aria-label="Permalink to &quot;HTML Renderer&quot;">​</a></h2><p><code>HtmlLayoutRenderer</code> produces a complete <code>&lt;!DOCTYPE html&gt;</code> document with embedded CSS. The <code>.board</code> div uses absolute positioning for all keys; the document has no external dependencies.</p><h3 id="key-rendering" tabindex="-1">Key Rendering <a class="header-anchor" href="#key-rendering" aria-label="Permalink to &quot;Key Rendering&quot;">​</a></h3><p>Each key is a <code>position: absolute</code> div placed at its board-space coordinates. The key&#39;s outer div uses <code>box-shadow: inset</code> for the 1px border, which keeps the border entirely within the element&#39;s layout bounds.</p><p><strong>Border overlap</strong>: Each key div is rendered 1 pixel larger than its nominal cell size. Adjacent keys therefore overlap by 1px. Because both borders are inset, they cover the same pixel and produce a single visible edge — matching the appearance of physical adjacent keys. The inner cap&#39;s CSS offsets absorb this extra pixel so the cap surface size is correct.</p><p><strong>Rotation</strong>: Rotated keys receive CSS <code>transform: rotate(...)</code> with a <code>transform-origin</code> expressed relative to the key div&#39;s top-left corner (the renderer converts board-space origin to element-relative coordinates).</p><h3 id="special-key-types" tabindex="-1">Special Key Types <a class="header-anchor" href="#special-key-types" aria-label="Permalink to &quot;Special Key Types&quot;">​</a></h3><ul><li><strong>Ghost</strong>: outer div gets <code>opacity: 0.3</code>.</li><li><strong>Decal</strong>: no outer or inner div; only labels are emitted in a plain positioned container.</li><li><strong>Homing nub</strong>: a small dark bar is added as an absolutely-positioned child div inside the key, centered horizontally and placed near the bottom of the inner cap.</li><li><strong>Rotary encoder</strong>: outer and inner divs both get <code>border-radius: 50%</code>; the inner div uses equal insets on all sides instead of the asymmetric bevel.</li></ul><h3 id="non-rectangular-keys" tabindex="-1">Non-rectangular Keys <a class="header-anchor" href="#non-rectangular-keys" aria-label="Permalink to &quot;Non-rectangular Keys&quot;">​</a></h3><p>Non-rectangular keys (ISO Enter, Big-Ass Enter) need two overlapping rectangles to form the shape. The HTML renderer uses a <code>0×0</code> overflow-visible container positioned at the primary rect&#39;s board coordinates, then emits both outer rects, a borderless filler div that covers the border seam at the junction, both inner cap rects, and finally the labels wrapper — all as absolutely positioned children of the container. The filler div is drawn after the second outer rect so its fill overpaints any inset shadow pixel that would otherwise be visible at the junction.</p><hr><h2 id="svg-renderer" tabindex="-1">SVG Renderer <a class="header-anchor" href="#svg-renderer" aria-label="Permalink to &quot;SVG Renderer&quot;">​</a></h2><p><code>SvgLayoutRenderer</code> produces a standalone SVG document rooted at <code>&lt;svg&gt;</code> with <code>overflow=&quot;visible&quot;</code> (so rotated keys that extend beyond the board boundary are not clipped).</p><h3 id="key-rendering-1" tabindex="-1">Key Rendering <a class="header-anchor" href="#key-rendering-1" aria-label="Permalink to &quot;Key Rendering&quot;">​</a></h3><p>Each key is wrapped in a <code>&lt;g&gt;</code> element. Rotated keys receive a <code>transform=&quot;rotate(angle, originX, originY)&quot;</code> attribute using the board-space origin directly (SVG&#39;s rotation transform takes an explicit origin, unlike CSS).</p><p>The outer rect is offset by 0.5px on both axes. SVG strokes are centered on the path, so an integer position would put half the stroke outside the nominal boundary. The 0.5px offset shifts the stroke center to the pixel boundary, making adjacent keys&#39; strokes overlap by exactly 1px — the same single-visible-border behavior as the HTML renderer.</p><h3 id="label-rendering" tabindex="-1">Label Rendering <a class="header-anchor" href="#label-rendering" aria-label="Permalink to &quot;Label Rendering&quot;">​</a></h3><p>The renderer handles three label content types:</p><ul><li><p><strong>Plain text</strong>: rendered as a <code>&lt;text&gt;</code> element. Multi-line text (word-wrapped using <code>CanvasRenderingContext2D.measureText</code>) uses <code>&lt;tspan&gt;</code> elements with <code>dy</code> offsets. The Y position of the first line is computed by <code>computeMultiLineStartY</code> so the baseline type aligns correctly for all line counts.</p></li><li><p><strong>Formatted text</strong>: when label text contains HTML tags (<code>&lt;b&gt;</code>, <code>&lt;strong&gt;</code>, <code>&lt;i&gt;</code>, <code>&lt;em&gt;</code>), it is parsed by <code>labelParser</code> into an AST and rendered as nested <code>&lt;tspan&gt;</code> elements with inline <code>font-weight</code> or <code>font-style</code> attributes.</p></li><li><p><strong>SVG images</strong>: when label text is itself an SVG document (matching a specific pattern), it is encoded as a Base64 data URL and rendered as an <code>&lt;image&gt;</code> element. Dimensions are taken from the SVG&#39;s own <code>width</code>/<code>height</code> attributes and clamped to the label&#39;s <code>maxWidth</code>/<code>maxHeight</code>.</p></li></ul><h3 id="non-rectangular-keys-1" tabindex="-1">Non-rectangular Keys <a class="header-anchor" href="#non-rectangular-keys-1" aria-label="Permalink to &quot;Non-rectangular Keys&quot;">​</a></h3><p>The SVG renderer uses the <code>polygon-clipping</code> library to compute the geometric union of the two rounded rectangles and emit a single <code>&lt;path&gt;</code> element per layer (outer bevel, inner cap). Each rectangle is approximated as a polygon with 8-segment arc corners, the union is computed, and the result is converted to an SVG <code>d</code> string. This eliminates the visible seam that would appear at the junction of two separately-stroked rectangles.</p><p>If the union computation throws, the renderer falls back to four separate <code>&lt;rect&gt;</code> elements drawn in the correct order so each successive fill covers the previous element&#39;s border seam.</p><hr><h2 id="integration" tabindex="-1">Integration <a class="header-anchor" href="#integration" aria-label="Permalink to &quot;Integration&quot;">​</a></h2><p>The standard pattern is:</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { normalizeLayoutInput, htmlLayoutRenderer, svgLayoutRenderer } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;@/utils/layout-export&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> input</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> normalizeLayoutInput</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(keys, metadata, filename)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> html</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> htmlLayoutRenderer.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">render</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(input)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> svg</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> svgLayoutRenderer.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">render</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(input)</span></span></code></pre></div><p><code>normalizeLayoutInput</code> can be called once and the resulting <code>LayoutRenderInput</code> passed to both renderers. To change output scale, pass a custom <code>unit</code> as the fourth argument (default is 54). Bevel and border constants do not scale with <code>unit</code>, so very small unit values will produce disproportionate bevels.</p><p>The application&#39;s integration point is <code>KeyboardToolbar.vue</code>, which uses the File System Access API (<code>showSaveFilePicker</code>) when available and falls back to a programmatic anchor download. A dismissed file picker dialog throws an <code>AbortError</code> that is silently ignored.</p><p>Both <code>htmlLayoutRenderer</code> and <code>svgLayoutRenderer</code> are module-level singleton exports. Use them in application code. Use <code>new HtmlLayoutRenderer()</code> / <code>new SvgLayoutRenderer()</code> in tests where per-test isolation is needed.</p><hr><h2 id="implementation-notes" tabindex="-1">Implementation Notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation Notes&quot;">​</a></h2><p><strong>Coordinate systems</strong>: Store coordinates (<code>Key.x</code>, <code>Key.y</code>) are in keyboard units. <code>KeyRenderData</code> coordinates are in board-space pixels with the minimum key corner at <code>(LAYOUT_PADDING, LAYOUT_PADDING)</code>. The HTML renderer additionally converts the rotation origin from board-space to element-relative pixels for the CSS <code>transform-origin</code> property.</p><p><strong><code>sanitizeLabelForHtml</code> vs <code>escapeHtml</code></strong>: These serve distinct purposes. <code>escapeHtml</code> escapes HTML special characters for use in element content and attributes (prevents tag injection). <code>sanitizeLabelForHtml</code> is applied to label text that appears inside JavaScript template literals in the generated HTML&#39;s <code>&lt;script&gt;</code>-adjacent context — it specifically prevents backtick and <code>&lt;/script</code> injection patterns that <code>escapeHtml</code> does not address.</p><p><strong>Canvas API dependency in SVG renderer</strong>: <code>SvgLayoutRenderer</code> calls <code>document.createElement(&#39;canvas&#39;)</code> to obtain a <code>CanvasRenderingContext2D</code> for text measurement during word-wrap. In non-browser environments the canvas creation is caught and <code>_measureCtx</code> is set to <code>null</code>, causing <code>wrapText</code> to return the full text as a single unwrapped line. Tests that exercise multi-line wrapping must stub <code>document.createElement</code> and reset <code>_measureCtx</code> to <code>undefined</code> between runs.</p><p><strong>Testing</strong>: The four spec files in <code>__tests__/</code> cover geometry functions, normalization logic, and both renderers. Run with <code>npx vitest run src/utils/layout-export</code>. Renderer tests verify output structure (number of elements, presence of attributes) rather than exact coordinates, making them robust to minor pixel-value changes.</p>`,67)])])}const g=a(s,[["render",r]]);export{u as __pageData,g as default};
